SourceCode.Declaration:
/// <summary>
/// Enabling attached sales agreement linkage for credit note
/// </summary>
[ExtensionOf(classStr(SalesCopying_CreditNote))]
final class ETGSalescopying_CreditNote_Extension
{
}

Method.Source:
void copy()
{
    SalesAgreementHeader salesAgreementHeader;
    SalesTable originalSalesTable;
    next copy();

    //todo check with team ifthis requirement needs any flag or parameter?

    if (custInvoiceJour.SalesId)
    {
        originalSalesTable = SalesTable::find(custInvoiceJour.SalesId);
    }
    if(!salesTable.Matchingagreement && originalSalesTable.RecId)
    {
        ttsbegin;
        salesTable.MatchingAgreement = originalSalesTable.MatchingAgreement;
        salesTable.update();
        ttscommit;
    }
}

void updateInvoiceCreditCopy(SalesLine _salesLine, CustVendInvoiceTrans _custVendInvoiceTrans)
{
    SalesLine originalSalesLine;
    next updateInvoiceCreditCopy(_salesLine, _custVendInvoiceTrans);

    //todo check with team ifthis requirement needs any flag or parameter?
    // Get original line using InventTransId
    if (_custVendInvoiceTrans.TableId == tableNum(CustInvoiceTrans))
    {
        CustInvoiceTrans custInvoiceTrans = _custVendInvoiceTrans;

        select firstonly originalSalesLine
            where originalSalesLine.InventTransId == custInvoiceTrans.InventTransId
               && originalSalesLine.SalesId       == custInvoiceTrans.SalesId;
    }

    if (originalSalesLine.RecId && !_salesLine.MatchingAgreementLine)
    {
        ttsbegin;
        _salesLine.MatchingAgreementLine = originalSalesLine.MatchingAgreementLine;
        _salesLine.update();
        ttscommit;
    }
}
